var maxAverageRatio = function(classes, extraStudents) {
    const delta = (p, t) => (t - p) / (t * (t + 1));
    const heap = [];
    const up = (i) => { while (i > 0) { const par = (i - 1) >> 1; if (heap[par][0] <= heap[i][0]) break; [heap[par], heap[i]] = [heap[i], heap[par]]; i = par; } };
    const down = (i) => { const m = heap.length; for (;;) { let s = i, l = 2 * i + 1, r = 2 * i + 2; if (l < m && heap[l][0] < heap[s][0]) s = l; if (r < m && heap[r][0] < heap[s][0]) s = r; if (s === i) break; [heap[s], heap[i]] = [heap[i], heap[s]]; i = s; } };
    const push = (x) => { heap.push(x); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    for (const [p, t] of classes) push([-delta(p, t), p, t]);
    for (let i = 0; i < extraStudents; i++) {
        const [d, p, t] = pop();
        const np = p + 1, nt = t + 1;
        push([-delta(np, nt), np, nt]);
    }
    let total = 0;
    for (const [d, p, t] of heap) total += p / t;
    return total / classes.length;
};
